import{_ as t,o as a,c as s,an as o}from"./chunks/framework.C3dNTM_d.js";const g=JSON.parse('{"title":"Customising your docs","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/customising.md","filePath":"getting-started/customising.md","lastUpdated":null}'),i={name:"getting-started/customising.md"};function r(n,e,d,c,l,h){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="customising" tabindex="-1">Customising your docs <a class="header-anchor" href="#customising" aria-label="Permalink to &quot;Customising your docs {#customising}&quot;">​</a></h1><p><code>scaffold</code> seeds a starting set of docs source pages once; after that they belong to the adopting package, not to the kit. This page explains which files are yours to rewrite and where to start.</p><h2 id="What&#39;s-package-owned-here" tabindex="-1">What&#39;s package-owned here <a class="header-anchor" href="#What&#39;s-package-owned-here" aria-label="Permalink to &quot;What&#39;s package-owned here {#What&#39;s-package-owned-here}&quot;">​</a></h2><p><code>update</code> never rewrites these, no matter how many times it runs:</p><ul><li><p><code>getting-started/index.md</code> — the quickstart a new user lands on first.</p></li><li><p><code>getting-started/infrastructure.md</code> and any further page added under <code>docs/src/</code>.</p></li><li><p><code>docs/pages.jl</code> — the navigation tree; add, remove, or reorder entries freely.</p></li><li><p>The README body (only the badge block between the managed markers is rewritten on sync; everything else is package-owned).</p></li></ul><p>See <a href="/previews/PR127/getting-started/infrastructure#infrastructure">Infrastructure and template sync</a> for the full managed-versus-package-owned breakdown.</p><h2 id="Making-it-your-own" tabindex="-1">Making it your own <a class="header-anchor" href="#Making-it-your-own" aria-label="Permalink to &quot;Making it your own {#Making-it-your-own}&quot;">​</a></h2><ul><li><p>Replace the seeded quickstart in <code>getting-started/index.md</code> with the package&#39;s real installation steps and a runnable first example.</p></li><li><p>Add new pages under <code>docs/src/</code> as the package grows (tutorials, guides, worked examples), then list them in <code>docs/pages.jl</code>.</p></li><li><p>Reorder or rename any <code>Getting started</code> entry; <code>pages.jl</code> is read fresh on every <code>docs/make.jl</code> run, so there is no drift to fight.</p></li><li><p>Keep or delete this page once it has served its purpose — it is package-owned like the rest of <code>getting-started/</code>.</p></li></ul><p>The kit&#39;s own copies of these pages (the ones this documentation site renders) are the worked example: this site is a real adopter of the scaffold, seeded once and then hand-edited the same way any adopting package&#39;s docs would be.</p><h2 id="What-stays-managed" tabindex="-1">What stays managed <a class="header-anchor" href="#What-stays-managed" aria-label="Permalink to &quot;What stays managed {#What-stays-managed}&quot;">​</a></h2><ul><li><p><code>docs/make.jl</code>, the thin caller into the kit&#39;s build logic.</p></li><li><p>The VitePress theme, config, and components under <code>docs/src/.vitepress/</code> and <code>docs/src/components/</code>.</p></li><li><p>The API reference pages, generated fresh from the module&#39;s docstrings on every build rather than stored as source.</p></li></ul><p>Editing a managed file directly works until the next <code>update</code> or template-sync run reverts it — put customisation in the package-owned files above instead.</p>',12)])])}const u=t(i,[["render",r]]);export{g as __pageData,u as default};
